public class Solution {
    public static long solve(long n, long[][] edges) {
        int numNodes = (int) n;
        List<List<int[]>> graph = new ArrayList<>();
        List<List<int[]>> reversedGraph = new ArrayList<>();
        for (int i = 0; i < numNodes; i++) {
            graph.add(new ArrayList<>());
            reversedGraph.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int w = (int) edge[2];
            graph.get(u).add(new int[]{v, w});
            reversedGraph.get(v).add(new int[]{u, w});
        }

        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[2]));
        long[][] dist = new long[numNodes][2];
        for (int i = 0; i < numNodes; i++) {
            dist[i][0] = Long.MAX_VALUE;
            dist[i][1] = Long.MAX_VALUE;
        }
        dist[0][0] = 0;
        pq.offer(new long[]{0, 0, 0});

        while (!pq.isEmpty()) {
            long[] curr = pq.poll();
            int u = (int) curr[0];
            int used = (int) curr[1];
            long cost = curr[2];

            if (u == numNodes - 1) {
                return cost;
            }

            if (cost > dist[u][used]) {
                continue;
            }

            // Normal edges
            for (int[] edge : graph.get(u)) {
                int v = edge[0];
                int w = edge[1];
                if (dist[v][used] > cost + w) {
                    dist[v][used] = cost + w;
                    pq.offer(new long[]{v, used, dist[v][used]});
                }
            }

            // If not used switch yet, consider reversing an incoming edge
            if (used == 0) {
                for (int[] edge : reversedGraph.get(u)) {
                    int v = edge[0];
                    int w = edge[1];
                    if (dist[v][1] > cost + 2 * w) {
                        dist[v][1] = cost + 2 * w;
                        pq.offer(new long[]{v, 1, dist[v][1]});
                    }
                }
            }
        }

        long res = Math.min(dist[numNodes - 1][0], dist[numNodes - 1][1]);
        return res == Long.MAX_VALUE ? -1 : res;
    }
}
