            int w = (int) edge[2];
            graph.get(u).add(new int[]{v, w});
            reverseGraph.get(v).add(new int[]{u, w});
        }

        // dist[node][used]: min cost to reach node with used (0 or 1)
        long[][] dist = new long[numNodes][2];
        for (int i = 0; i < numNodes; i++) {
            Arrays.fill(dist[i], Long.MAX_VALUE);
        }
        dist[0][0] = 0;

        PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[1]));
        pq.offer(new long[]{0, 0, 0}); // node, cost, used

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            int u = (int) current[0];
            long cost = current[1];
            int used = (int) current[2];

            if (u == numNodes - 1) {
                return cost;
            }

            if (cost > dist[u][used]) {
                continue;
            }

            // Normal edges
            for (int[] edge : graph.get(u)) {
                int v = edge[0];
                int w = edge[1];
                if (dist[v][used] > cost + w) {
                    dist[v][used] = cost + w;
                    pq.offer(new long[]{v, dist[v][used], used});
                }
            }

            // Try to use the switch at u (if not used yet)
            if (used == 0) {
                for (int[] edge : reverseGraph.get(u)) {
                    int v = edge[0]; // original u is v in reverse edge
                    int w = edge[1];
                    if (dist[v][1] > cost + 2L * w) {
                        dist[v][1] = cost + 2L * w;
                        pq.offer(new long[]{v, dist[v][1], 1});
                    }
                }
            }
        }

        long res = Math.min(dist[numNodes - 1][0], dist[numNodes - 1][1]);
        return res == Long.MAX_VALUE ? -1 : res;
    }
