                    dist[v][1] = currentDist + 2L * w;
                    pq.offer(new long[]{v, 1, dist[v][1]});
                }
            }
        }
    }

    long result = Math.min(dist[numNodes - 1][0], dist[numNodes - 1][1]);
    return result == Long.MAX_VALUE ? -1 : result;
}
